<template>
  <h3 class="title">Add Your Workout</h3>
  <form class="form-container" @submit.prevent="saveWorkout">
    <div class="inputs">
      <input
        class="form-input"
        type="text"
        placeholder="Workout name.."
        required
        v-model="workoutName"
      />
      <input
        class="form-input"
        type="text"
        placeholder="Workout reps.."
        required
        v-model="workoutReps"
      />
      <input
        class="form-input"
        type="text"
        placeholder="Workout sets.."
        required
        v-model="workoutSets"
      />
      <button class="form-button">Add</button>
    </div>
  </form>
  <div>
    <h3>Saved Workouts</h3>
    <h5 class="empty-workouts" v-if="workouts.length === 0">
      No workouts added
    </h5>
    <div class="saved-workouts">
      <ul>
        <li v-for="(workout, index) in workouts" :key="index">
          <div class="saved-workouts-container">
            <h4>Date: {{ dateString() }}</h4>
            <p>
              Workout: {{ workout.name }} - Reps: {{ workout.reps }} - Sets:
              {{ workout.sets }}
              <button @click="deleteWorkout(index)">X</button>
            </p>
          </div>
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
import { ref } from "@vue/reactivity";

export default {
  setup() {
    const workoutName = ref("");
    const workoutReps = ref("");
    const workoutSets = ref("");
    const defaultData = [];

    const datestring = ref("");

    const dateString = () => {
      const date = new Date();
      const day = date.getDate();
      const month = date.getMonth() + 1;
      const year = date.getFullYear();
      const datestring = year + "-" + month + "-" + day;
      return datestring;
    };

    const workoutsData =
      JSON.parse(localStorage.getItem("workouts")) || defaultData;
    const workouts = ref(workoutsData);

    const saveData = () => {
      const storageData = JSON.stringify(workouts.value);
      localStorage.setItem("workouts", storageData);
    };
    const saveWorkout = () => {
      if (
        workoutName.value == "" ||
        workoutReps.value == "" ||
        workoutSets.value == ""
      ) {
        return;
      } else {
        workouts.value.push({
          name: workoutName.value,
          reps: workoutReps.value,
          sets: workoutSets.value,
          date: dateString(),
        });
        workoutName.value = "";
        workoutReps.value = "";
        workoutSets.value = "";
      }
      saveData();
    };
    const deleteWorkout = (index) => {
      workouts.value.splice(index, 1);
      saveData();
    };

    return {
      workoutName,
      workoutReps,
      workoutSets,
      workouts,
      saveWorkout,
      deleteWorkout,
      saveData,
      datestring,
      dateString,
    };
  },
};
</script>

<style>
.title {
  margin-top: 50px;
  font-size: 26px;
  /*border: 1px solid black;*/
}
.form-container {
  /*border: 1px solid black;*/
  margin: 10px auto;
  max-width: 200px;
}
form button {
  width: 70px;
  height: 35px;
  background-color: beige;
  border-radius: 10px;
  border: none;
  cursor: pointer;
  margin-top: 25px;
}
.form-input {
  width: 150px;
  height: 30px;
  font-size: 18px;
  text-align: center;
  margin-top: 25px;
  border: none;
  border-bottom: 1px solid black;
}
ul {
  list-style: none;
}
.saved-workouts-container {
  /*border: 1px solid black;*/
  text-align: center;
  margin: 10px auto;
  max-width: 400px;
  margin-top: 40px;
}
.saved-workouts h4 {
  /*border: 1px solid black;*/
  text-align: left;
  padding: 10px;
}
.saved-workouts p {
  /*border: 1px solid black;*/
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px;
  text-align: left;
  background-color: beige;
  border-radius: 5px;
}
.saved-workouts button {
  border: none;
  text-align: end;
  background-color: beige;
  cursor: pointer;
  font-size: 18px;
  font-weight: bold;
}
.empty-workouts {
  font-weight: 100;
  font-style: italic;
  font-size: 14px;
}
</style>
